import sys

def solve(data: str) -> str:
    start, steps = map(int, data.split())
    def make_counter(initial: int):
        current = initial
        def advance() -> int:
            nonlocal current
            current += 1
            return current
        return advance

    counter = make_counter(start)
    return ' '.join(str(counter()) for _ in range(steps))

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
